import { isArray } from '../../../../utils/zcutils';
import { CHART_DOMAIN_HELPERS } from '../../../../brush/chart-helpers/domain-helpers';
import { getAxisObject } from '../../../../axis/axisutils';
import { updateScaleByTransform } from '../../../data-selection/chart/tools/transform-scale';
import { getIdentity } from '../tools/zoom-identity-by-domain';
import { constrainDomain } from '../../../data-selection/chart/tools/selection-to-domain';
import { mathAbs } from '../../../../core/zc-constants';
import { _ZoomToDomain } from './zoom-to-domain';

/**
 *
 * @param behaviourEventInstance
 * @param selectionManager
 * @param selection
 * @constructor
 */
export function SCROLL_BRUSH_ACTION(behaviourEventInstance, selectionManager, selection, event) {
    let eventManager = this,
        scroll = behaviourEventInstance.instance,
        behaviours = eventManager.behaviours,
        chart = scroll.chart,
        domainInfo = selectionManager.point,
        domain = domainInfo.x.domain,
        plotBrushInstanceMap = behaviours.PLOT_BRUSH,
        plotZoomInstanceMap = behaviours.PLOT_ZOOM,
        range = scroll.brushScale.range(),
        chartXScale = chart.axes.x.scale;

    chart.viewPortExtent = domain;

    scroll.lastScroll = selection.map(scroll.scrollPositionScale.invert);
    // fix the outer padding
    // if (!scroll.isSmooth) {
    //     if (!scroll.isSingleDomain) {
    //         if (scroll.brushScale.bandwidth) {
    //             let factor = scroll.rotated || chart.axes.x.reverse ? -1 : -1;
    //             range = [range[0] - chartXScale.outerPaddingPx * factor, range[1] + chartXScale.outerPaddingPx * factor];
    //         } else {
    //             domain = applyPadding(domain, chartXScale.outerPadding, chartXScale.originalDomain, chartXScale.correctionOverBubbles);
    //         }
    //     }
    //      #FEATURES_SCROLL_6 extra padding
    //     // domainInfo.x.range = range;
    //     // domainInfo.x.domain = domain;
    // }

    // let selectionCache = chart.cache.scroll.selection,
    // isDuplicateScroll = selectionCache && selectionCache[0] === selection[0] && selectionCache[1] === selection[1];

    // save the selection
    chart.cache.scroll.selection = selection;
    chart.cache.scroll.domain = domain;

    // #ZC2455 $isDuplicateScroll
    // #[ZC2357] [line, $chart.scrolling]
    var isRedraw = scroll.chart.phase;
    if(event.sourceEvent || isRedraw){
        chart.scrolling_ = true;
        //sourceEvent will be not be there initially. SourceEvent for scroll.
        //setting it to true in initial rendering will call filter chart twice and it affects the chart's animation.
    }
    
    if (chart.zooming || (chart.scrolling && !chart.scrollEnd)) {
    // if (chart.zooming) {
        return;
    }
    if(chart.scrollEnd){
        chart.scrollEnd = false;
    }
    chart.scroll.scrollDomain = domain;

    // #[ZC2357] disable the animation only while scroll by user
    chart.disableAnimation = !!event.sourceEvent;
    chart.scrolling = true;

    if (isArray(domain)) {
        if (plotZoomInstanceMap) {
            domain = [domain[0], domain[domain.length - 1]];
            let identity = getIdentity(chart, domain, 'x', 0, selection);
            plotZoomInstanceMap.instance.zoomToIdentity(identity, 0);
            // _ZoomToDomain(eventManager, domain, 'x', 0, chart.brushScale, 0);
        } else {
            if (scroll.settings.smooth === true) {
                smoothOrdinalScroll(domainInfo, selection, scroll, chart, range);
            } else {
                CHART_DOMAIN_HELPERS.FILTER_CHART(domainInfo, scroll.chart);
            }
        }

        if (plotBrushInstanceMap) {
            plotBrushInstanceMap.instance.updateExtent([
                [0, 0],
                [chart.plotarea.width, chart.plotarea.height]
            ]);
        }
    }

    if (scroll.tooltip && event.sourceEvent) {
        scroll.tooltip.show();
    }

    clearTimeout(scroll.timer);
    scroll.timer = setTimeout(() => ((chart.scrolling = false), (chart.disableAnimation = false)), 50);
}

export function applyPadding(domain, padding, calculatedPadding) {
    let isDate = domain[0] instanceof Date;
    if (isDate) {
        domain = domain.map(d => d.getTime());
    }
    if (isArray(calculatedPadding)) {
        domain = [domain[0] - calculatedPadding[0], domain[1] + calculatedPadding[1]];
    } else {
        let correction = mathAbs(domain[1] - domain[0]) * padding;
        domain = [domain[0] - correction, domain[1] + correction];
    }

    if (isDate) {
        domain = domain.map(d => new Date(d));
    }
    return domain;
}

/**
 *
 * @param domain
 * @param xScale
 * @return {(number|*)[]|*}
 */
function fixDomainCorrection(domain, xScale) {
    if (xScale.bandwidth) {
        return domain;
    }

    let isDate = domain[0] instanceof Date,
        correction = xScale.correction;
    domain = domain.slice(0);
    if (isDate) {
        domain = domain.map(d => d.getTime());
    }
    domain = [domain[0] - correction, domain[1] + correction];

    if (isDate) {
        domain = domain.map(d => new Date(d));
    }
    domain = constrainDomain(domain, xScale.originalDomain, xScale.outerPadding);
    return domain;
}
/**
 *
 * @param domainInfo
 * @param selection
 * @param scroll
 * @param chart
 */
function smoothOrdinalScroll(domainInfo, selection, scroll, chart, scrollRange) {
    let transform = getIdentity(chart, domainInfo.x.domain, 'x', 0, selection),
        type = 'x',
        { scale, orient, reversed } = getAxisObject(chart, type, 0),
        axisInfo = { scale, baseScale: scroll.brushScale, orient, reversed },
        { range, domain } = updateScaleByTransform(axisInfo, chart.axes.rotated ? 'y' : 'x', transform, scrollRange);

    scroll.transform = transform;
    domainInfo.x.range = range;
    domainInfo.x.domain = domain;

    CHART_DOMAIN_HELPERS.FILTER_CHART(domainInfo, chart);
}
